    text = await getBubble();
    console.log(`${i+2}:`, text);
    if (!text) break;
  }

  await page.waitForTimeout(300);

  // Accept quest
  await page.evaluate(() => {
    const btn = document.getElementById('quest-button');
    if (btn) btn.click();
  });
  await page.waitForTimeout(1500);

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    const anvil = s.quests.find(q => q.key === 'anvilsechoes');
    return JSON.stringify({ anvil, inventory: s.inventory, pos: s.player_position });
  });
  return state;
}

